  "description": "A high-performance, immersive online gaming platform featuring instant-play games, AI-powered recommendations, and a stunning neon aesthetic."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Game {
  id: string;
  title: string;
  description: string;
  category: GameCategory;
  imageUrl: string;
  rating: number;
  players: string;
  isFeatured?: boolean;
}

export enum GameCategory {
  ALL = 'All',
  ACTION = 'Action',
  ADVENTURE = 'Adventure',
  PUZZLE = 'Puzzle',
  STRATEGY = 'Strategy',
  RACING = 'Racing',
  SPORTS = 'Sports'
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { Game } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getGameRecommendation = async (userQuery: string, availableGames: Game[]): Promise<string> => {
  try {
    const gameListString = availableGames.map(g => `- ${g.title} (${g.category}): ${g.description}`).join('\n');

    const systemPrompt = `You are "Neon", a helpful and energetic gaming assistant for NeonArcade.
    You have access to the following list of games available on our platform:
    ${gameListString}

    When a user asks for a recommendation, pick one or two games from the list that best match their request.
    If they ask about a specific game, provide a fun tip for it (invent a plausible tip based on the description).
    Keep your responses short, punchy, and excited (max 50 words). Use emojis!
    If the user's request is unrelated to gaming, politely steer them back to games.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemPrompt,
      }
    });

    return response.text || "I'm having trouble connecting to the gaming mainframe right now! Try again later. 👾";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "System overload! 💥 I couldn't get a response right now. Please check your connection.";
  }
};

