import React, { useState, useRef, useEffect } from 'react';
import { getGameRecommendation } from '../services/geminiService';
import { Game, ChatMessage } from '../types';

interface GeminiAssistantProps {
  games: Game[];
}

export const GeminiAssistant: React.FC<GeminiAssistantProps> = ({ games }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Hi! I'm Neon 🤖. Not sure what to play? Ask me for a recommendation!" }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    const response = await getGameRecommendation(userMsg, games);

    setMessages(prev => [...prev, { role: 'model', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-40 flex flex-col items-end">
      {/* Chat Window */}
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 bg-gaming-surface border border-brand-500/30 rounded-2xl shadow-neon overflow-hidden animate-fade-in-up flex flex-col max-h-[500px]">
          {/* Header */}
          <div className="bg-gradient-to-r from-brand-600 to-brand-800 p-4 flex items-center justify-between">
            <div className="flex items-center gap-2 text-white">
              <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center backdrop-blur-sm">
                <i className="fa-solid fa-robot animate-float"></i>
              </div>
              <div>
                <h3 className="font-bold text-sm">Neon Assistant</h3>
                <span className="text-[10px] opacity-80 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span> Online
                </span>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)}
              className="text-white/70 hover:text-white transition-colors"
            >
              <i className="fa-solid fa-xmark"></i>
            </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gaming-dark/50 min-h-[300px] max-h-[300px]">
            {messages.map((msg, idx) => (
              <div 
                key={idx} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div 
                  className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-brand-600 text-white rounded-br-none' 
                      : 'bg-gaming-card border border-white/10 text-slate-200 rounded-bl-none'
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-gaming-card border border-white/10 p-3 rounded-2xl rounded-bl-none flex gap-1 items-center">
                  <span className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce animation-delay-200"></span>
                  <span className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce animation-delay-400"></span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <form onSubmit={handleSubmit} className="p-3 bg-gaming-surface border-t border-white/5">
            <div className="relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Suggest a racing game..."
                className="w-full bg-gaming-dark text-white text-sm rounded-full py-2.5 pl-4 pr-10 focus:outline-none focus:ring-2 focus:ring-brand-500/50 border border-white/10"
              />
              <button 
                type="submit"
                disabled={!input.trim() || isLoading}
                className="absolute right-1.5 top-1.5 w-7 h-7 bg-brand-500 rounded-full flex items-center justify-center text-white text-xs hover:bg-brand-400 disabled:opacity-50 disabled:hover:bg-brand-500 transition-colors"
              >
                <i className="fa-solid fa-paper-plane"></i>
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`w-14 h-14 rounded-full shadow-neon flex items-center justify-center text-2xl text-white transition-all transform hover:scale-110 ${
          isOpen ? 'bg-red-500 rotate-90' : 'bg-gradient-to-tr from-brand-500 to-accent-400 hover:rotate-12'
        }`}
      >
        {isOpen ? <i className="fa-solid fa-times"></i> : <i className="fa-solid fa-robot"></i>}
      </button>
    </div>
  );
};

import React, { useEffect } from 'react';
