  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/80 backdrop-blur-md transition-opacity"
        onClick={onClose}
      ></div>

      {/* Modal Content */}
      <div className="relative w-full max-w-5xl bg-gaming-surface border border-white/10 rounded-2xl shadow-2xl overflow-hidden flex flex-col h-[80vh] animate-blob-in">

        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-white/10 bg-gaming-dark">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-lg overflow-hidden">
               <img src={game.imageUrl} alt={game.title} className="w-full h-full object-cover" />
             </div>
             <div>
               <h3 className="text-white font-bold text-lg leading-tight">{game.title}</h3>
               <p className="text-slate-400 text-xs">{game.category}</p>
             </div>
          </div>
          <button 
            onClick={onClose}
            className="w-8 h-8 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors"
          >
            <i className="fa-solid fa-xmark"></i>
          </button>
        </div>

        {/* Game Area (Iframe Placeholder) */}
        <div className="flex-1 bg-black relative flex items-center justify-center">
          <div className="text-center p-8">
            <div className="w-20 h-20 mx-auto bg-brand-500/20 rounded-full flex items-center justify-center mb-4 animate-pulse">
              <i className="fa-solid fa-gamepad text-4xl text-brand-500"></i>
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">Ready to Play?</h2>
            <p className="text-slate-400 max-w-md mx-auto mb-6">
              This is a demo. In a real application, the game iframe for <span className="text-brand-400">{game.title}</span> would load here.
            </p>
            <button className="px-6 py-2 bg-brand-600 hover:bg-brand-500 text-white rounded-full font-bold transition-all shadow-neon">
              Start Game
            </button>
          </div>

          {/* Simulated loading bar */}
          <div className="absolute bottom-0 left-0 w-full h-1 bg-white/10">
            <div className="h-full bg-gradient-to-r from-brand-500 to-accent-400 w-[60%]"></div>
          </div>
        </div>

        {/* Controls / Info */}
        <div className="p-4 bg-gaming-dark border-t border-white/10 flex justify-between items-center text-slate-400 text-sm">
          <div className="flex gap-4">
            <span className="flex items-center gap-2"><i className="fa-solid fa-arrows-up-down-left-right"></i> Move</span>
            <span className="flex items-center gap-2"><i className="fa-regular fa-keyboard"></i> Space to Jump</span>
          </div>
          <div className="flex gap-4">
             <button className="hover:text-white"><i className="fa-solid fa-expand"></i> Fullscreen</button>
             <button className="hover:text-white"><i className="fa-solid fa-share-nodes"></i> Share</button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
