  const [selectedCategory, setSelectedCategory] = useState<GameCategory>(GameCategory.ALL);
  const [activeGame, setActiveGame] = useState<Game | null>(null);

  // Filter games
  const filteredGames = useMemo(() => {
    if (selectedCategory === GameCategory.ALL) return GAMES;
    return GAMES.filter(g => g.category === selectedCategory);
  }, [selectedCategory]);

  // Featured Game (Random or specific)
  const featuredGame = GAMES.find(g => g.isFeatured) || GAMES[0];

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header />

      <main className="flex-grow">
        {/* Hero Section */}
        <Hero featuredGame={featuredGame} onPlay={setActiveGame} />

