        {/* Promotional Section */}
        <section className="py-16 bg-gradient-to-r from-brand-900/50 to-gaming-dark border-y border-white/5 relative overflow-hidden">
           <div className="absolute top-0 right-0 w-64 h-64 bg-accent-500/10 rounded-full blur-3xl"></div>
           <div className="container mx-auto px-4 relative z-10 text-center">
             <h2 className="font-titan text-4xl mb-6 text-white">Join the Neon Elite</h2>
             <p className="text-slate-300 max-w-2xl mx-auto mb-8 text-lg">
               Unlock exclusive skins, ad-free gaming, and join tournaments with huge prize pools.
             </p>
             <button className="px-10 py-4 bg-white text-gaming-dark font-black uppercase tracking-wider rounded-full hover:bg-brand-200 transition-colors transform hover:scale-105 shadow-[0_0_30px_rgba(255,255,255,0.3)]">
               Sign Up Free
             </button>
           </div>
        </section>
      </main>

      {/* Footer */}
      <footer className="bg-gaming-dark border-t border-white/5 pt-16 pb-8">
        <div className="container mx-auto px-4">
          <div className="grid md:grid-cols-4 gap-12 mb-12">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-2 mb-6">
                 <div className="w-10 h-10 flex items-center justify-center bg-brand-500 rounded-lg text-white">
                   <i className="fa-solid fa-gamepad text-xl"></i>
                 </div>
                 <span className="font-titan text-2xl text-white">NeonArcade</span>
              </div>
              <p className="text-slate-400 mb-6 max-w-sm">
                The ultimate destination for free online gaming. Play instantly, no downloads required. Experience the future of browser gaming.
              </p>
              <div className="flex gap-4">
                {['twitter', 'discord', 'instagram', 'youtube'].map(icon => (
                  <a key={icon} href="#" className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-slate-400 hover:bg-brand-500 hover:text-white transition-all">
                    <i className={`fa-brands fa-${icon}`}></i>
                  </a>
                ))}
              </div>
            </div>

            <div>
              <h4 className="font-bold text-white mb-6 uppercase tracking-wider text-sm">Discover</h4>
              <ul className="space-y-3 text-slate-400 text-sm">
                {['New Releases', 'Most Popular', 'Editors Choice', 'Surprise Me'].map(item => (
                  <li key={item}><a href="#" className="hover:text-brand-400 transition-colors">{item}</a></li>
                ))}
              </ul>
            </div>

             <div>
              <h4 className="font-bold text-white mb-6 uppercase tracking-wider text-sm">Support</h4>
              <ul className="space-y-3 text-slate-400 text-sm">
                {['Help Center', 'Terms of Service', 'Privacy Policy', 'Contact Us'].map(item => (
                  <li key={item}><a href="#" className="hover:text-brand-400 transition-colors">{item}</a></li>
                ))}
