            </div>
          </div>

          <div className="border-t border-white/5 pt-8 text-center text-slate-600 text-xs">
            &copy; {new Date().getFullYear()} NeonArcade Gaming Inc. All rights reserved.
          </div>
        </div>
      </footer>

      {/* Game Modal */}
      {activeGame && (
        <GameModal game={activeGame} onClose={() => setActiveGame(null)} />
      )}

      {/* AI Assistant */}
      <GeminiAssistant games={GAMES} />
    </div>
  );
}

